import { ChangeEvent, FormEvent, useEffect, useMemo, useState } from "react";
import {
  createAnalysis,
  getAnalysesForResume,
  getErrorMessage,
  healthCheck,
  loginUser,
  registerUser,
  uploadResume
} from "./api";
import { generateAnalysis, parseJsonList } from "./analysisEngine";
import { Analysis, Resume, Session } from "./types";

const SESSION_KEY = "resumeai.session";

const formatBytes = (bytes?: number) => {
  if (!bytes) {
    return "Ready";
  }
  const units = ["B", "KB", "MB"];
  let size = bytes;
  let unitIndex = 0;
  while (size >= 1024 && unitIndex < units.length - 1) {
    size /= 1024;
    unitIndex += 1;
  }
  return `${size.toFixed(size >= 10 ? 0 : 1)} ${units[unitIndex]}`;
};

const loadSession = (): Session | null => {
  const raw = localStorage.getItem(SESSION_KEY);
  if (!raw) {
    return null;
  }

  try {
    return JSON.parse(raw) as Session;
  } catch {
    localStorage.removeItem(SESSION_KEY);
    return null;
  }
};

export default function Dashboard() {
  const [session, setSession] = useState<Session | null>(() => loadSession());
  const [authMode, setAuthMode] = useState<"login" | "register">("login");
  const [username, setUsername] = useState("");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [jobDescription, setJobDescription] = useState("");
  const [focusSkills, setFocusSkills] = useState("Java, Spring Boot, React");
  const [resume, setResume] = useState<Resume | null>(null);
  const [analysis, setAnalysis] = useState<Analysis | null>(null);
  const [history, setHistory] = useState<Analysis[]>([]);
  const [apiStatus, setApiStatus] = useState("checking");
  const [busy, setBusy] = useState(false);
  const [message, setMessage] = useState("");

  useEffect(() => {
    healthCheck()
      .then(setApiStatus)
      .catch(() => setApiStatus("offline"));
  }, []);

  useEffect(() => {
    if (session) {
      localStorage.setItem(SESSION_KEY, JSON.stringify(session));
    } else {
      localStorage.removeItem(SESSION_KEY);
    }
  }, [session]);

  const score = Math.round(analysis?.score || 0);
  const skills = useMemo(() => parseJsonList(analysis?.skills), [analysis]);
  const recommendations = useMemo(
    () => parseJsonList(analysis?.recommendations),
    [analysis]
  );

  const handleAuth = async (event: FormEvent) => {
    event.preventDefault();
    setBusy(true);
    setMessage("");

    try {
      if (authMode === "register") {
        const user = await registerUser(username, email, password);
        setSession({ user, password: username });
        setMessage("Account created. You can upload a resume now.");
      } else {
        const response = await loginUser(username, password);
        if (!response.user) {
          throw new Error("Login response did not include a user.");
        }
        setSession({ user: response.user, token: response.token, password: username });
        setMessage(response.message || "Signed in.");
      }
    } catch (error) {
      setMessage(getErrorMessage(error));
    } finally {
      setBusy(false);
    }
  };

  const handleFileChange = (event: ChangeEvent<HTMLInputElement>) => {
    setSelectedFile(event.target.files?.[0] || null);
  };

  const handleAnalyze = async (event: FormEvent) => {
    event.preventDefault();
    if (!selectedFile) {
      setMessage("Choose a PDF or DOCX resume first.");
      return;
    }

    setBusy(true);
    setMessage("");

    try {
      const uploaded = await uploadResume(selectedFile, session);
      const generated = generateAnalysis(selectedFile, jobDescription, focusSkills);
      const saved = await createAnalysis(
        {
          resumeId: uploaded.id,
          ...generated
        },
        session
      );
      const savedHistory = await getAnalysesForResume(uploaded.id, session);
      setResume(uploaded);
      setAnalysis(saved);
      setHistory(savedHistory);
      setMessage("Resume uploaded and analysis saved.");
    } catch (error) {
      setMessage(getErrorMessage(error));
    } finally {
      setBusy(false);
    }
  };

  const signOut = () => {
    setSession(null);
    setResume(null);
    setAnalysis(null);
    setHistory([]);
    setMessage("Signed out.");
  };

  return (
    <main className="min-h-screen bg-[#f6f7fb]">
      <header className="border-b border-slate-200 bg-white">
        <div className="mx-auto flex max-w-7xl flex-col gap-4 px-4 py-5 sm:flex-row sm:items-center sm:justify-between lg:px-8">
          <div>
            <p className="text-xs font-semibold uppercase tracking-wide text-teal-700">
              ResumeAI
            </p>
            <h1 className="text-2xl font-semibold text-slate-950">
              Resume analysis workspace
            </h1>
          </div>
          <div className="flex flex-wrap items-center gap-3 text-sm">
            <span className="rounded-full border border-slate-200 bg-slate-50 px-3 py-1 text-slate-700">
              API: {apiStatus}
            </span>
            {session ? (
              <>
                <span className="text-slate-600">{session.user.username}</span>
                <button
                  className="rounded-md bg-slate-900 px-4 py-2 font-medium text-white hover:bg-slate-700"
                  onClick={signOut}
                  type="button"
                >
                  Sign out
                </button>
              </>
            ) : null}
          </div>
        </div>
      </header>

      <div className="mx-auto grid max-w-7xl gap-6 px-4 py-6 lg:grid-cols-[360px_1fr] lg:px-8">
        <aside className="space-y-6">
          <section className="rounded-lg border border-slate-200 bg-white p-5 shadow-soft">
            <div className="mb-4 flex rounded-md bg-slate-100 p-1">
              {(["login", "register"] as const).map((mode) => (
                <button
                  key={mode}
                  className={`flex-1 rounded px-3 py-2 text-sm font-semibold ${
                    authMode === mode
                      ? "bg-white text-slate-950 shadow-sm"
                      : "text-slate-600"
                  }`}
                  onClick={() => setAuthMode(mode)}
                  type="button"
                >
                  {mode === "login" ? "Login" : "Register"}
                </button>
              ))}
            </div>

            <form className="space-y-3" onSubmit={handleAuth}>
              <label className="block text-sm font-medium text-slate-700">
                Username
                <input
                  className="mt-1 w-full rounded-md border border-slate-300 px-3 py-2"
                  onChange={(event) => setUsername(event.target.value)}
                  required
                  value={username}
                />
              </label>
              {authMode === "register" ? (
                <label className="block text-sm font-medium text-slate-700">
                  Email
                  <input
                    className="mt-1 w-full rounded-md border border-slate-300 px-3 py-2"
                    onChange={(event) => setEmail(event.target.value)}
                    required
                    type="email"
                    value={email}
                  />
                </label>
              ) : null}
              <label className="block text-sm font-medium text-slate-700">
                Password
                <input
                  className="mt-1 w-full rounded-md border border-slate-300 px-3 py-2"
                  onChange={(event) => setPassword(event.target.value)}
                  required
                  type="password"
                  value={password}
                />
              </label>
              <button
                className="w-full rounded-md bg-teal-700 px-4 py-2 font-semibold text-white hover:bg-teal-800 disabled:cursor-not-allowed disabled:bg-slate-400"
                disabled={busy}
                type="submit"
              >
                {authMode === "login" ? "Login" : "Create account"}
              </button>
            </form>
          </section>

          <section className="rounded-lg border border-slate-200 bg-white p-5 shadow-soft">
            <h2 className="text-base font-semibold text-slate-950">Resume file</h2>
            <form className="mt-4 space-y-4" onSubmit={handleAnalyze}>
              <label className="flex min-h-36 cursor-pointer flex-col items-center justify-center rounded-lg border-2 border-dashed border-slate-300 bg-slate-50 px-4 py-6 text-center hover:border-teal-500">
                <span className="text-sm font-semibold text-slate-800">
                  {selectedFile ? selectedFile.name : "Choose PDF or DOCX"}
                </span>
                <span className="mt-1 text-xs text-slate-500">
                  {selectedFile ? formatBytes(selectedFile.size) : "Up to 16 MB"}
                </span>
                <input
                  accept=".pdf,.doc,.docx,application/pdf,application/vnd.openxmlformats-officedocument.wordprocessingml.document"
                  className="sr-only"
                  onChange={handleFileChange}
                  type="file"
                />
              </label>

              <label className="block text-sm font-medium text-slate-700">
                Target skills
                <input
                  className="mt-1 w-full rounded-md border border-slate-300 px-3 py-2"
                  onChange={(event) => setFocusSkills(event.target.value)}
                  value={focusSkills}
                />
              </label>

              <label className="block text-sm font-medium text-slate-700">
                Job description
                <textarea
                  className="mt-1 min-h-32 w-full resize-y rounded-md border border-slate-300 px-3 py-2"
                  onChange={(event) => setJobDescription(event.target.value)}
                  value={jobDescription}
                />
              </label>

              <button
                className="w-full rounded-md bg-slate-900 px-4 py-2 font-semibold text-white hover:bg-slate-700 disabled:cursor-not-allowed disabled:bg-slate-400"
                disabled={busy || !selectedFile}
                type="submit"
              >
                Upload and analyze
              </button>
            </form>
          </section>
        </aside>

        <section className="space-y-6">
          {message ? (
            <div className="rounded-lg border border-teal-200 bg-teal-50 px-4 py-3 text-sm text-teal-900">
              {message}
            </div>
          ) : null}

          <div className="grid gap-4 md:grid-cols-3">
            <div className="rounded-lg border border-slate-200 bg-white p-5 shadow-soft">
              <p className="text-sm text-slate-500">Resume</p>
              <p className="mt-2 truncate text-lg font-semibold text-slate-950">
                {resume?.filename || "No upload yet"}
              </p>
              <p className="mt-1 text-sm text-slate-500">
                {formatBytes(resume?.fileSize)}
              </p>
            </div>
            <div className="rounded-lg border border-slate-200 bg-white p-5 shadow-soft">
              <p className="text-sm text-slate-500">Fit score</p>
              <p className="mt-2 text-4xl font-semibold text-slate-950">{score}</p>
              <p className="mt-1 text-sm text-slate-500">out of 100</p>
            </div>
            <div className="rounded-lg border border-slate-200 bg-white p-5 shadow-soft">
              <p className="text-sm text-slate-500">Analyses</p>
              <p className="mt-2 text-4xl font-semibold text-slate-950">
                {history.length}
              </p>
              <p className="mt-1 text-sm text-slate-500">saved for this resume</p>
            </div>
          </div>

          <div className="grid gap-6 xl:grid-cols-[1fr_360px]">
            <section className="rounded-lg border border-slate-200 bg-white p-5 shadow-soft">
              <div className="flex items-center justify-between gap-4">
                <h2 className="text-lg font-semibold text-slate-950">Skills match</h2>
                <span className="text-sm text-slate-500">
                  {analysis?.createdAt ? new Date(analysis.createdAt).toLocaleString() : ""}
                </span>
              </div>
              <div className="mt-5 flex flex-wrap gap-2">
                {skills.length ? (
                  skills.map((skill) => (
                    <span
                      className="rounded-full bg-teal-50 px-3 py-1 text-sm font-medium text-teal-800"
                      key={skill}
                    >
                      {skill}
                    </span>
                  ))
                ) : (
                  <p className="text-sm text-slate-500">
                    Upload a resume to populate matched skills.
                  </p>
                )}
              </div>

              <h3 className="mt-8 text-base font-semibold text-slate-950">
                Recommendations
              </h3>
              <div className="mt-3 space-y-3">
                {recommendations.length ? (
                  recommendations.map((item) => (
                    <div
                      className="rounded-md border border-slate-200 bg-slate-50 p-3 text-sm text-slate-700"
                      key={item}
                    >
                      {item}
                    </div>
                  ))
                ) : (
                  <p className="text-sm text-slate-500">
                    Recommendations will appear after analysis.
                  </p>
                )}
              </div>
            </section>

            <section className="rounded-lg border border-slate-200 bg-white p-5 shadow-soft">
              <h2 className="text-lg font-semibold text-slate-950">History</h2>
              <div className="mt-4 space-y-3">
                {history.length ? (
                  history.map((item, index) => (
                    <button
                      className="w-full rounded-md border border-slate-200 p-3 text-left hover:border-teal-500"
                      key={`${item.id || index}-${item.createdAt || index}`}
                      onClick={() => setAnalysis(item)}
                      type="button"
                    >
                      <span className="block text-sm font-semibold text-slate-900">
                        Score {Math.round(item.score || 0)}
                      </span>
                      <span className="mt-1 block text-xs text-slate-500">
                        {item.createdAt
                          ? new Date(item.createdAt).toLocaleString()
                          : "Saved analysis"}
                      </span>
                    </button>
                  ))
                ) : (
                  <p className="text-sm text-slate-500">
                    Saved analyses for the latest uploaded resume appear here.
                  </p>
                )}
              </div>
            </section>
          </div>
        </section>
      </div>
    </main>
  );
}
